B.KT=new A.i("feature_consume_digest","Digest","After consuming, gain {Half Source} d12 Regeneration.")
B.HU=new A.i("feature_consume_feast","Feast","You may consume a body twice. If you have bite, you may bite a target twice.")
B.X7=s([B.Lo,B.KT,B.HU],t.U)
B.NF=new A.a8("feature_consume","Consume","[Action] You consume an adjacent Defeated Body, healing {Source d12} and gaining {Source d12} shield. A body may only be consumed once. The body must be defeated to be consumed.\n\n[Reaction] When a creature in range 3 of you dies, you may spend your [reaction] to dash to a free space adjacent to the body and consume the body.",B.T,B.X7,!1)
B.LT=new A.i("feature_corrosion_blinding","Blinding","While burning the target has disadvantage on ranged attacks and a -1 to results of melee attacks.")
B.Kw=new A.i("feature_corrosion_debilitating","Debilitating","While burning the target, you and your allies have +1 on status check results and the target\u2019s speed is reduce by {Half Source}")
