B.K2=new A.i("feature_hack_denied","Denied","While concentrating, [Reaction] When the target would use a [Reaction] make a status check vs Int. On Success, the target loses their reaction and their ability doesn\u2019t trigger.")
B.IA=new A.i("feature_hack_public_exploit","Public Exploit","On Success, you and your allies' attacks against targets have a +1 bonus to the result and deal extra {Half Source d6} damage.")
