B.Ok=new A.a8("feature_step","Step","[Action] Target you or a creature range 1, Teleport up to a free space range {2*Source}. If you target an enemy, make a Melee Attack vs Int, On success deal {Source d6} in addition to teleporting. On problems they do not teleport. \n\n[Reaction] At the end of any turn, target you or a creature range 1 and teleport them to a free space range {2*Source}. If you target an enemy, make a Melee Attack vs Int, On success deal {Source d6} in addition to teleporting. On problems they do not teleport. \n",B.T,B.V5,!1)
B.MB=new A.i("feature_sting_petrifying","Petrifying","If you Success with the Status Check, the target\u2019s speed is reduced to 0 until the start of your next turn.")
B.LJ=new A.i("feature_sting_neuroToxin","NeuroToxin","If you Success with the Status Check or reaction, the target has disadvantage on all Attacks until the start of your next turn.")
B.Jw=new A.i("feature_sting_ovipositor","Ovipositor","If you succeed with the status check or reaction, the target gains {Half Source}d6 Bleed.  After they cure this bleed, they gain {Half Source}d6 bleed.")
