B.Lt=new A.i("feature_wave_Surf","Surf","You are also pushed in the same direction then may dash up to {source} in either perpendicular direction.")
B.M0=new A.i("feature_wave_Tsunami","Tsunami","On Success, all enemies adjacent to you are also pushed. The distance of the push is increased by {source}.")
