B.a3R=new A.bp("Huckable","Increase range of abilities by {Level/3}")
B.a3U=new A.bp("Dangerous","Target all characters range 1 of any of the targets and deal {Level/3 d6} damage to them.")
B.a40=new A.bp("Dampening","Target all enemies range {Level/3} of any of the targets and reduce their shields by {Level/3 d6}.")
B.a3V=new A.bp("Energizing","Target all Allies range {Level/3} of any of the targets and they gain {Level/3} speed until the end of their next turn.")
